def solution(n: int = 1000):
    total = 0
    MOD = 10**10
    # Iterate from 1 to n inclusive
    for i in range(1, n + 1):
        # Use modular exponentiation to keep numbers small
        total = (total + pow(i, i, MOD)) % MOD

    # Ensure 10 digits with zero-padding
    return str(total).zfill(10)


if __name__ == "__main__":
    print(solution(1000))
